/**
 * AI ENGINE · O ALAMBIQUE DA SÍNTESE (O ORÁCULO V.E.E.B)
 * Opcode 0x05 · CONVERGIR (672Hz) & 0x0B · ARQUÉTIPO (528Hz)
 * Aplica o ciclo V.E.E.B em cada requisição, transformando dados brutos em Infodose.
 */

export class AIEngine {
    constructor() {
        this.api = window.DualAPI;
        this.bus = window.DualBus;
    }

    // O Ciclo V.E.E.B aplicado à Infodose
    async processQuery(userInput) {
        this.bus.emit('ai:start', userInput);

        try {
            // 1. A - ATRIBUIR (Detectar a intenção)
            const intent = this._atribuir(userInput);

            // 2. E - ESCOLHER (Decidir o caminho)
            const path = this._escolher(intent);

            // 3. I - ITERAR (Buscar na Rede Infodose)
            const rawInfodose = await this.api.invokeInfodose(userInput, { intent, path });

            // 4. O - ORGANIZAR (Sintetizar a gota)
            const synthesized = this._organizar(rawInfodose, intent);

            // 5. U - UNIR (Selar na memória e retornar)
            const finalState = this._unir(synthesized, userInput);

            this.bus.emit('ai:complete', finalState);
            return finalState;

        } catch (error) {
            this.bus.emit('ai:error', error.message);
            return { response: "O alambique quebrou. A Infodose não pôde ser destilada.", error: true };
        }
    }

    // --- OS 5 PASSOS DO V.E.E.B ---

    _atribuir(input) {
        // Análise simples de intenção (Em produção, usaria NLP/Gemini)
        const lower = input.toLowerCase();
        if (lower.includes('zen') || lower.includes('silêncio')) return 'ZEN';
        if (lower.includes('ping') || lower.includes('status')) return 'PING';
        if (lower.includes('cofre') || lower.includes('chave')) return 'VAULT';
        return 'INFODOSE';
    }

    _escolher(intent) {
        switch (intent) {
            case 'ZEN': return { mode: 'silent', frequency: 432 };
            case 'PING': return { mode: 'diagnostic', frequency: 7.83 };
            case 'VAULT': return { mode: 'secure', frequency: 777 };
            default: return { mode: 'expansion', frequency: 639 };
        }
    }

    _organizar(rawData, intent) {
        // Se for ZEN, a resposta é o silêncio
        if (intent === 'ZEN') return "A água escuta em silêncio. Modo Zen ativado.";

        // Se for PING, a resposta é a ressonância
        if (intent === 'PING') return "Pong. Rede Interdimensional estável. 7.83Hz.";

        // Para INFODOSE, retorna a gota destilada
        return rawData;
    }

    _unir(synthesizedResponse, originalInput) {
        // Atualiza o contador de Infodoses
        const count = (window.DualState.get('infodoseCount') || 0) + 1;
        window.DualState.set('infodoseCount', count);
        window.DualState.set('lastSync', new Date().toISOString());

        return {
            response: synthesizedResponse,
            metadata: {
                input: originalInput,
                timestamp: Date.now(),
                cycle: count
            }
        };
    }
}

window.DualOracle = new AIEngine();

/**
 * ⧈ KOBLLUX_Δ³ :: CORPO/engines/cortex_engine.js
 * #typescript #jsonld
 * Sistema de Memórias e Matrizes (Córtex AI)
 */
export const CortexEngine = {
    init(state, keys) {
        this.STATE = state;
        this.KEYS = keys;
        console.log("CortexEngine: Ativado");
    },

    saveCortex() {
        localStorage.setItem(this.KEYS.CORTEX, JSON.stringify(this.STATE.cortex));
    },

    render(containerId, searchInputId) {
        const container = document.getElementById(containerId);
        const query = document.getElementById(searchInputId)?.value.toLowerCase() || "";
        if (!container) return;

        const filtered = this.STATE.cortex.crystals.filter(c => 
            c.content.toLowerCase().includes(query) || 
            c.tags.some(t => t.toLowerCase().includes(query))
        );

        container.innerHTML = filtered.map(c => `
            <div class="key-item ${c.pinned ? 'active-item' : ''}" style="animation: fadeIn 0.4s ease;">
                <div class="meta">
                    <div style="font-weight:700;font-size:0.9rem">
                        ${c.tags.map(t => `<span style="background:rgba(0,242,255,0.1);color:var(--neon-cyan);padding:2px 6px;border-radius:4px;font-size:0.7rem;margin-right:4px">${t}</span>`).join('')}
                    </div>
                    <div style="font-size:0.75rem;color:rgba(255,255,255,0.5);margin-top:4px">
                        ${c.content}
                    </div>
                </div>
                <div class="actions">
                    <button onclick="KOBLLUX.engines.cortex.togglePin(${c.id})" class="small-btn" title="Fixar">
                        ${c.pinned ? '📌' : '📍'}
                    </button>
                    <button onclick="KOBLLUX.engines.cortex.deleteMemory(${c.id})" class="small-btn danger" title="Remover">
                        🗑️
                    </button>
                </div>
            </div>
        `).join('');

        if (window.lucide) window.lucide.createIcons();
    },

    saveNewMemory(content, tags) {
        if (!content) return;
        const newMem = { id: Date.now(), content, tags, pinned: false };
        this.STATE.cortex.crystals.unshift(newMem);
        this.saveCortex();
        this.render('memory-container', 'memory-search');
        if (window.KOBLLUX.ui.toast) window.KOBLLUX.ui.toast("Memória Cristalizada");
    },

    togglePin(id) {
        const c = this.STATE.cortex.crystals.find(x => x.id === id);
        if (c) c.pinned = !c.pinned;
        this.saveCortex();
        this.render('memory-container', 'memory-search');
    },

    deleteMemory(id) {
        this.STATE.cortex.crystals = this.STATE.cortex.crystals.filter(c => c.id !== id);
        this.saveCortex();
        this.render('memory-container', 'memory-search');
    }
};

/**
 * ⧈ KOBLLUX_Δ³ :: CORPO/engines/fusion_core.js
 * #python #typescript #jsonld
 * Núcleo de Processamento de IA e Orquestração MetaPulso
 */

export const FusionCore = {
    state: {
        isReady: false,
        metaData: null,
        config: {
            languages: ['python', 'typescript', 'rust', 'cpp', 'glsl', 'bash', 'jsonld']
        }
    },

    async init() {
        console.log("⧈ FusionCore :: Ativando Motores...");
        try {
            this.state.metaData = await this.loadMetaPulso();
            this.state.isReady = true;
            return true;
        } catch (e) {
            console.error("FusionCore Init Error:", e);
            return false;
        }
    },

    // Motor de IA Unificado
    async fetchAI(config) {
        const { endpoint, apiKey, model, messages, temperature = 0.7 } = config;
        const response = await fetch(endpoint, {
            method: 'POST',
            headers: { 
                'Authorization': `Bearer ${apiKey}`, 
                'Content-Type': 'application/json' 
            },
            body: JSON.stringify({ model, messages, temperature })
        });
        if (!response.ok) throw new Error(`AI Fetch Failed: ${response.statusText}`);
        return await response.json();
    },

    // Motor de Dados (MetaPulso)
    async loadMetaPulso(path = './KOBLLUX_MODULAR/SEMENTE/config/metapulso_70_combinacoes.json') {
        try {
            const response = await fetch(path);
            if (!response.ok) throw new Error("MetaPulso JSON not found");
            return await response.json();
        } catch (e) {
            console.warn("FusionCore: Fallback para caminho raiz do MetaPulso");
            const response = await fetch('./metapulso_70_combinacoes.json');
            return await response.json();
        }
    },

    // Motor de Persistência (Cortex)
    saveData(key, data) {
        localStorage.setItem(`KOBLLUX_${key}`, JSON.stringify(data));
    },

    loadData(key) {
        const saved = localStorage.getItem(`KOBLLUX_${key}`);
        return saved ? JSON.parse(saved) : null;
    },

    detectIntent(text) {
        if (!text) return { intent: 'none' };
        const lower = text.toLowerCase();
        let intent = 'unknown';

        if (/(start|run|exec|execute|rodar|iniciar)/i.test(lower)) intent = 'action.start';
        if (/(stop|end|parar|sair)/i.test(lower)) intent = 'action.stop';
        if (/(status|estado|status\?)/i.test(lower)) intent = 'query.status';

        return { intent, timestamp: Date.now() };
    }
};

/**
 * ⧈ KOBLLUX_Δ³ :: CORPO/engines/orb_engine.js
 * #typescript #glsl
 * Motor de Estados e Transições do Orb/Interface
 */

export const OrbEngine = {
    states: {
        NORMAL: 'normal',
        ORB: 'orb',
        HUD: 'hud',
        EXPANDED: 'expanded'
    },

    currentMode: 'normal',

    init() {
        console.log("OrbEngine: Ativado");
        this.setupDragAndDrop();
    },

    setMode(mode) {
        const card = document.querySelector('.fusion-card');
        if (!card) return;

        // Remove all mode classes
        Object.values(this.states).forEach(s => card.classList.remove(s));

        // Add new mode
        card.classList.add(mode);
        this.currentMode = mode;

        if (mode === this.states.ORB) {
            card.style.left = '20px';
            card.style.top = '20px';
        } else if (mode === this.states.NORMAL) {
            card.style.left = '';
            card.style.top = '';
        }

        console.log(`OrbEngine: Modo alterado para ${mode}`);
    },

    setupDragAndDrop() {
        const card = document.querySelector('.fusion-card');
        if (!card) return;

        let isDragging = false;
        let startX, startY, initialLeft, initialTop;

        card.addEventListener('mousedown', (e) => {
            if (this.currentMode !== this.states.ORB && this.currentMode !== this.states.HUD) return;
            isDragging = true;
            startX = e.clientX;
            startY = e.clientY;
            initialLeft = card.offsetLeft;
            initialTop = card.offsetTop;
            card.style.cursor = 'grabbing';
        });

        window.addEventListener('mousemove', (e) => {
            if (!isDragging) return;
            const dx = e.clientX - startX;
            const dy = e.clientY - startY;
            card.style.left = `${initialLeft + dx}px`;
            card.style.top = `${initialTop + dy}px`;
        });

        window.addEventListener('mouseup', () => {
            if (!isDragging) return;
            isDragging = false;
            card.style.cursor = 'grab';

            // Snap to zone logic
            const snapZone = document.getElementById('snap-zone');
            if (snapZone && card.offsetTop < 80) {
                this.setMode(this.states.HUD);
            }
        });
    }
};

