/**
 * ⧈ KOBLLUX_Δ³ :: CORPO/logic/crypto_vault.js
 * #rust #typescript
 * Lógica de Criptografia e Segurança (AES-GCM)
 * Δ7: Segurança e Concorrência (Rust) / Gestão de Estado (TypeScript)
 */

export const CryptoVault = {
    algo: { name: 'AES-GCM', length: 256 },
    pbkdf2: { name: 'PBKDF2', hash: 'SHA-256', iterations: 100000 },

    async getKey(password, salt) {
        const enc = new TextEncoder();
        const keyMaterial = await window.crypto.subtle.importKey(
            "raw", 
            enc.encode(password), 
            "PBKDF2", 
            false, 
            ["deriveKey"]
        );
        return window.crypto.subtle.deriveKey(
            { ...this.pbkdf2, salt: salt }, 
            keyMaterial, 
            this.algo, 
            false, 
            ["encrypt", "decrypt"]
        );
    },

    async encrypt(data, password) {
        const salt = window.crypto.getRandomValues(new Uint8Array(16));
        const iv = window.crypto.getRandomValues(new Uint8Array(12));
        const key = await this.getKey(password, salt);
        const encoded = new TextEncoder().encode(JSON.stringify(data));
        const encrypted = await window.crypto.subtle.encrypt(
            { name: "AES-GCM", iv: iv }, 
            key, 
            encoded
        );
        const bundle = { 
            s: Array.from(salt), 
            iv: Array.from(iv), 
            d: Array.from(new Uint8Array(encrypted)) 
        };
        return JSON.stringify(bundle);
    },

    async decrypt(bundleStr, password) {
        try {
            const bundle = JSON.parse(bundleStr);
            const salt = new Uint8Array(bundle.s);
            const iv = new Uint8Array(bundle.iv);
            const data = new Uint8Array(bundle.d);
            const key = await this.getKey(password, salt);
            const decrypted = await window.crypto.subtle.decrypt(
                { name: "AES-GCM", iv: iv }, 
                key, 
                data
            );
            return JSON.parse(new TextDecoder().decode(decrypted));
        } catch(e) { 
            throw new Error("Senha incorreta ou dados corrompidos"); 
        }
    }
};

/**
 * EVENT BUS · O SISTEMA NERVOSO AUTÔNOMO
 * Opcode 0x02 · INTEGRAR · 528Hz (TypeScript - A Reta que Conecta)
 * Permite que os polos (Head, Body, Script) comuniquem sem acoplamento direto.
 */

export class EventBus {
    constructor() {
        this.listeners = new Map();
        this.history = []; // O testemunho do fluxo (Opcode 0x08)
    }

    // Escutar uma frequência (evento)
    on(event, callback) {
        if (!this.listeners.has(event)) {
            this.listeners.set(event, []);
        }
        this.listeners.get(event).push(callback);
    }

    // Emitir um pulso (verbo em ação)
    emit(event, data) {
        const pulse = { event, data, timestamp: Date.now() };
        this.history.push(pulse);

        // Limitar o histórico para não corromper a memória (Schumann 7.83Hz)
        if (this.history.length > 1134) {
            this.history.shift();
        }

        if (this.listeners.has(event)) {
            this.listeners.get(event).forEach(callback => {
                try {
                    callback(data);
                } catch (error) {
                    console.error(`[EVENT BUS] Ruptura no polo ${event}:`, error);
                }
            });
        }
    }

    // Cancelar a escuta (desconectar o polo)
    off(event, callback) {
        if (this.listeners.has(event)) {
            const filtered = this.listeners.get(event).filter(cb => cb !== callback);
            this.listeners.set(event, filtered);
        }
    }
}

// Instância global (O Espírito que permeia tudo)
window.DualBus = new EventBus();

/**
 * ⧈ KOBLLUX_Δ³ :: CORPO/logic/state_manager.js
 * #typescript
 * Gestão Central de Estado e Sincronização
 */
export const StateManager = {
    state: {
        user: { name: "PILOTO", id: "001" },
        triad: { color: 'Azul', essence: 'Silêncio', element: 'Água' },
        cortex: { crystals: [], matrices: [] },
        ui: { mode: 'normal', theme: 'dark' }
    },

    init() {
        console.log("StateManager: Ativado");
        this.loadLocalState();
    },

    loadLocalState() {
        const saved = localStorage.getItem('KOBLLUX_STATE');
        if (saved) {
            this.state = { ...this.state, ...JSON.parse(saved) };
        }
    },

    saveState() {
        localStorage.setItem('KOBLLUX_STATE', JSON.stringify(this.state));
    },

    update(path, value) {
        const parts = path.split('.');
        let current = this.state;
        for (let i = 0; i < parts.length - 1; i++) {
            current = current[parts[i]];
        }
        current[parts[parts.length - 1]] = value;
        this.saveState();
        this.notify(path, value);
    },

    notify(path, value) {
        // Usa o EventBus global se disponível, senão CustomEvent
        if (window.DualBus) {
            window.DualBus.emit('state:changed', { path, value });
        } else {
            window.dispatchEvent(new CustomEvent('kobllux-state-change', { 
                detail: { path, value } 
            }));
        }
    }
};

/**
