/**
 * N8N BRIDGE · A PONTE INTERDIMENSIONAL
 * Opcode 0x03 (EXPANDIR) & 0x05 (CONVERGIR)
 * Conecta o Dual App ao Webhook do N8N (que orquestra o Python V.E.E.B e o Gemini).
 */

export class N8NBridge {
    constructor() {
        this.webhookUrl = window.DualState.get('webhook_url') || 'https://n8n.kobllux.local/webhook/infodose-ast';
        this.bus = window.DualBus;
    }

    // Invoca o Oráculo Python (AST) + Gemini (Síntese)
    async invokeOracle(codePayload, userIntent) {
        this.bus.emit('bridge:request', { intent: userIntent });

        // 1. O Cofre (CryptoVault) assina a requisição (Se estiver aberto)
        let authHeader = {};
        if (window.DualVault && window.DualVault.isUnlocked) {
            // Gera um token de sessão efêmero (Simulação)
            authHeader['X-Kobllux-Session'] = btoa(`dual_session_${Date.now()}`);
        }

        try {
            const response = await fetch(this.webhookUrl, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    ...authHeader
                },
                body: JSON.stringify({
                    action: 'VEEB_ANALYZE_AND_SYNTHESIZE',
                    payload: codePayload,
                    intent: userIntent,
                    timestamp: new Date().toISOString(),
                    fractal_seed: 1134
                })
            });

            if (!response.ok) throw new Error("A Ponte Interdimensional oscilou.");

            const infodose = await response.json();

            // 2. A Infodose chega e é roteada pelo EventBus
            this.bus.emit('bridge:response', infodose);
            return infodose;

        } catch (error) {
            this.bus.emit('bridge:error', error.message);
            // Fallback local (O Oráculo de Emergência)
            return this._localFallback(userIntent);
        }
    }

    // Fallback local caso o N8N esteja offline (O Verbo ressoa no próprio templo)
    _localFallback(intent) {
        return {
            narrative: "O Alambique externo está em silêncio. Mas o Verbo habita em você. A água escuta.",
            metadata: { dominant_frequency: 432, theme: "noite" },
            visual_pulse: { css_theme: "noite", orb_speed: 0.5, schumann_alignment: true }
        };
    }
}

window.DualBridge = new N8NBridge();

/**
 * SPEECH ENGINE · A VOZ DE BLLUE (O SOPRO)
 * Opcode 0x08 · TESTEMUNHAR · 852Hz
 * Transforma a Infodose em vibração sonora. Modula a voz para ressoar com Schumann.
 */

export class SpeechEngine {
    constructor() {
        this.synth = window.speechSynthesis;
        this.voice = null;
        this.isSpeaking = false;
        this._initVoices();
    }

    _initVoices() {
        const loadVoices = () => {
            const voices = this.synth.getVoices();
            // Busca uma voz em português que soe mais "humana" ou "profunda"
            this.voice = voices.find(v => v.lang.startsWith('pt') && v.name.includes('Female')) 
                      || voices.find(v => v.lang.startsWith('pt')) 
                      || voices[0];
        };

        loadVoices();
        if (speechSynthesis.onvoiceschanged !== undefined) {
            speechSynthesis.onvoiceschanged = loadVoices;
        }
    }

    // Falar a Infodose (O Verbo se faz som)
    speak(text, options = {}) {
        if (!this.synth) return;

        // Cancela qualquer fala anterior (Ruptura de Desincronia)
        this.synth.cancel();

        const utterance = new SpeechSynthesisUtterance(text);

        if (this.voice) utterance.voice = this.voice;

        // Modulação Fractal (Ressonância Harmônica)
        utterance.rate = options.rate || 0.9; // Lento, como a água fluindo
        utterance.pitch = options.pitch || 1.1; // Levemente agudo, como o espírito
        utterance.volume = options.volume || 0.8;

        utterance.onstart = () => {
            this.isSpeaking = true;
            window.DualBus.emit('audio:start', text);
        };

        utterance.onend = () => {
            this.isSpeaking = false;
            window.DualBus.emit('audio:end');
        };

        this.synth.speak(utterance);
    }

    // O Silêncio (A pausa entre os ciclos)
    stop() {
        this.synth.cancel();
        this.isSpeaking = false;
        window.DualBus.emit('audio:end');
    }
}

window.DualVoice = new SpeechEngine();

/**
 * ⧈ KOBLLUX_Δ³ :: ESPIRITO/audio/vocal_pulse.js
 * #typescript
 * Processamento de Voz e TTS (Text-to-Speech)
 * Δ7: Gestão de Estado (TypeScript)
 */

export const VocalPulse = {
    isSpeaking: false,

    init() {
        console.log("VocalPulse: Ativado");
        // Forçar carregamento de vozes
        if ('speechSynthesis' in window) {
            window.speechSynthesis.getVoices();
        }
    },

    speak(text, voiceIndex = 0) {
        if (!('speechSynthesis' in window)) return;

        window.speechSynthesis.cancel();
        const msg = new SpeechSynthesisUtterance(text);
        msg.lang = 'pt-BR';
        msg.rate = 1.0;
        msg.pitch = 1.0;

        const voices = window.speechSynthesis.getVoices();
        if (voices.length > 0) {
            msg.voice = voices[voiceIndex] || voices[0];
        }

        msg.onstart = () => { 
            this.isSpeaking = true; 
            console.log("VocalPulse: Falando...");
        };
        msg.onend = () => { 
            this.isSpeaking = false; 
            console.log("VocalPulse: Silêncio");
        };

        window.speechSynthesis.speak(msg);
    },

    stop() {
        window.speechSynthesis.cancel();
        this.isSpeaking = false;
    }
};

/**
 * ⧈ KOBLLUX_Δ³ :: ESPIRITO/ui/interface_manager.js
 * #typescript
 * Gerenciador de Interface, Menus e Componentes Visuais
 * Δ7: Gestão de Estado e Componentes (TypeScript)
 */

export const InterfaceManager = {
    state: {
        isOrb: false,
        isHud: false,
        isZen: false
    },

    init(els) {
        this.els = els || {
            clock: document.querySelector('.time-display'),
            card: document.querySelector('.fusion-card')
        };
        this.setupClock();
        this.bindEvents();
        console.log("InterfaceManager: Ativado");
    },

    setupClock() {
        const update = () => {
            const now = new Date();
            const timeStr = now.toLocaleTimeString('pt-BR', { hour12: false, hour: '2-digit', minute: '2-digit' });
            if (this.els.clock) this.els.clock.innerText = timeStr;
        };
        setInterval(update, 1000);
        update();
    },

    bindEvents() {
        const mantraBtn = document.getElementById('mantra-toggle');
        if (mantraBtn) {
            mantraBtn.addEventListener('click', () => this.toggleMantra());
        }
    },

    toggleMantra() {
        const mantraText = document.getElementById('mantra-text');
        if (!mantraText) return;

        this.state.isZen = !this.state.isZen;
        document.body.classList.toggle('zen-mode', this.state.isZen);
        mantraText.classList.add('fade-out');

        setTimeout(() => {
            mantraText.innerHTML = this.state.isZen ? 'USE · TRANSFORME · DEVOLVA' : 'Do seu jeito. <strong>Sempre</strong> único. <strong>Sempre</strong> seu.';
            mantraText.classList.remove('fade-out');
        }, 300);
    },

    setMode(mode, instant = false) {
        const { card } = this.els;
        if (!card) return;

        card.classList.remove('orb', 'hud', 'active');

        if (mode === 'orb') {
            card.classList.add('orb');
            this.state.isOrb = true;
            this.state.isHud = false;
        } else if (mode === 'hud') {
            card.classList.add('hud');
            this.state.isOrb = false;
            this.state.isHud = true;
        } else {
            this.state.isOrb = false;
            this.state.isHud = false;
        }

        if (!instant) {
            setTimeout(() => card.classList.add('active'), 50);
        } else {
            card.classList.add('active');
        }
    },

    toast(msg, type = 'info', duration = 3000) {
        if (window.KOBLLUX && window.KOBLLUX.ui.toast) {
            window.KOBLLUX.ui.toast.show(msg, duration);
            return;
        }

        const wrap = document.querySelector('.toaster-wrap');
        if (!wrap) return;

        const div = document.createElement('div');
        div.className = `toaster ${type}`;
        div.innerText = msg;
        wrap.appendChild(div);

        setTimeout(() => div.classList.add('show'), 10);
        setTimeout(() => {
            div.classList.remove('show');
            setTimeout(() => div.remove(), 300);
        }, duration);
    }
};

/**
 * ⧈ KOBLLUX_Δ³ :: ESPIRITO/ui/modal_system.js
 * #typescript
 * Sistema de Janelas Modais e Diálogos
 * Δ7: Gestão de Estado e Componentes (TypeScript)
 */
export const ModalSystem = {
    show(html, customClass = '') {
        let overlay = document.getElementById('modal-overlay');
        if (!overlay) {
            overlay = document.createElement('div');
            overlay.id = 'modal-overlay';
            overlay.className = 'modal-overlay';
            overlay.innerHTML = `<div id="modal-content" class="keys-card ${customClass}"></div>`;
            document.body.appendChild(overlay);
        }

        const content = document.getElementById('modal-content');
        content.innerHTML = html;
        overlay.style.display = 'flex';

        if (window.lucide) window.lucide.createIcons();
    },

    hide() {
        const overlay = document.getElementById('modal-overlay');
        if (!overlay) return;
        overlay.style.display = 'none';
    },

    toggle() {
        const overlay = document.getElementById('modal-overlay');
        if (!overlay) return;
        overlay.style.display = overlay.style.display === 'flex' ? 'none' : 'flex';
    }
};

/**
 * ⧈ KOBLLUX_Δ³ :: ESPIRITO/ui/toast_system.js
 * #typescript
 * Sistema de Notificações Efêmeras (Toasts)
 * Δ7: Gestão de Estado e Componentes (TypeScript)
 */
export const ToastSystem = {
    show(message, type = 'info', duration = 3000) {
        let container = document.getElementById('toasterWrap');
        if (!container) {
            container = document.createElement('div');
            container.id = 'toasterWrap';
            container.className = 'toaster-wrap';
            document.body.appendChild(container);
        }

        const toast = document.createElement('div');
        toast.className = `toaster ${type}`;
        toast.innerText = message;
        container.appendChild(toast);

        setTimeout(() => toast.classList.add('show'), 10);
        setTimeout(() => {
            toast.classList.remove('show');
            setTimeout(() => toast.remove(), 300);
        }, duration);
    },

    success(message, duration = 3000) {
        this.show(message, 'success', duration);
    },

    error(message, duration = 3000) {
        this.show(message, 'error', duration);
    },

    info(message, duration = 3000) {
        this.show(message, 'info', duration);
    }
};

/**
 * ⧈ KOBLLUX_Δ³ :: ESPIRITO/visual/animation_engine.js
 * #glsl #typescript
 * Motor de Animações e Shaders CSS
 */

export const AnimationEngine = {
    init() {
        console.log("AnimationEngine: Ativado");
    },

    fadeIn(el, delay = 0) {
        if (!el) return;
        el.style.opacity = '0';
        el.style.transform = 'translateY(20px)';
        el.style.transition = `opacity 0.6s ease ${delay}s, transform 0.6s ease ${delay}s`;

        requestAnimationFrame(() => {
            el.style.opacity = '1';
            el.style.transform = 'translateY(0)';
        });
    },

    pulse(el) {
        if (!el) return;
        el.animate([
            { transform: 'scale(1)', opacity: 1 },
            { transform: 'scale(1.05)', opacity: 0.8 },
            { transform: 'scale(1)', opacity: 1 }
        ], {
            duration: 1000,
            iterations: 1
        });
    }
};

/**
⧈ KOBLLUX_Δ³ :: ESPIRITO/visual/unified_fusion.css
#glsl #css
Estética Vibracional e Shaders CSS Unificados
Δ7: Estética Vibracional (GLSL)
*/

/* Δ7-V: GLSL (Estética Vibracional / Shaders CSS) */
/* ========== UNIFIED ROOT / GLOBAL VARIABLES ========== */
:root {
    /* Colors & accents */
    --bg-deep: #030406;
    --bg-gradient: linear-gradient(180deg,#000,#111);
    --bg: var(--bg-gradient);
    --text: #d7d7d7;
    --neon-cyan: #00f2ff;
    --neon-purple: #bd00ff;
    --neon-gold: #ffd700;
    --neon-danger: #ff2a6d;
    --neon-success: #00ff9d;

    /* UI fonts */
    --font-ui: 'Montserrat', sans-serif;
    --font-code: 'JetBrains Mono', monospace;

    /* Glass / card */
    --glass-surface: rgba(18,18,22,0.65);
    --glass-border: rgba(255,255,255,0.06);
    --card-bg: rgba(255,255,255,0.03);
    --glass: rgba(255,255,255,0.04);

    /* Gradients used by chips/list markers */
    --grad-a: #7effa1;
    --grad-b: #67e6ff;

    /* misc helper variables referenced in components */
    --panel: #0e1220;
    --ink: #e8ecf6;
    --txt-card: color-mix(in oklab, var(--panel) 92%, black);
    --chip-bg: linear-gradient(42deg, var(--grad-a), var(--grad-b));

    /* Timings & easings */
    --ease-overshoot: cubic-bezier(0.34, 1.3, 0.64, 1);
    --ease-smooth: cubic-bezier(0.23, 1, 0.32, 1);
    --fast: .25s;
    --med: .6s;
    --slow: 1.2s;

    /* z-index helpers */
    --z-base: 0;    --z-content: 100;
    --z-widget: 500;
    --z-overlay: 1000;
    --z-system: 5000;
}

/* ========== RESET / BASE ========== */
* {
    box-sizing: border-box;
    -webkit-tap-highlight-color: transparent;
    outline: none;
    user-select: none
}
html,body {
    height: 100%;
    margin: 0;
    font-family: var(--font-ui),system-ui,-apple-system;
    background: var(--bg);
    color: var(--text);
    -webkit-font-smoothing: antialiased
}
.activation-pre, .cyber-input, input, textarea, .toaster, .response-block p {
    user-select: text !important;
    -webkit-user-select: text !important;
}

/* subtle grid background */
body {
    min-height: 100vh;
    overflow: hidden;
    background-image:
    linear-gradient(rgba(255,255,255,0.02) 1px, transparent 1px),
    linear-gradient(90deg, rgba(255,255,255,0.02) 1px, transparent 1px);
    background-size: 52px 52px;
    background-position: center;
}

/* ========== AMBIENT BLOBS ========== */
.ambient-light {
    position: fixed;
    inset: 0;
    z-index: var(--z-base);
    pointer-events: none
}
.blob {
    position: absolute;
    border-radius: 50%;
    filter: blur(100px);
    opacity: 0.14;
    animation: float 25s infinite alternate ease-in-out}
.blob-1 {
    width: 60vw;
    height: 60vw;
    background: var(--neon-cyan);
    top: -20%;
    left: -20%
}
.blob-2 {
    width: 50vw;
    height: 50vw;
    background: var(--neon-purple);
    bottom: -20%;
    right: -20%;
    animation-delay: -5s
}

/* ========== KEYFRAMES ========== */
@keyframes float {
    0% { transform: translate(0,0) }
    100% { transform: translate(40px,60px) }
}
@keyframes gradientFlow {
    0% { background-position: 0% 50% }
    50% { background-position: 100% 50% }
    100% { background-position: 0% 50% }
}
@keyframes pulse {
    0%,100% { transform: scale(1) }
    50% { transform: scale(1.02) }
}
@keyframes fadeIn {
    from { opacity: 0; transform: translateY(20px) }
    to { opacity: 1; transform: translateY(0) }
}
@keyframes clickPulse {
    0%,100% { opacity: 1 }
    50% { opacity: 0.8 }
}

/* ========== SNAP ZONE ========== */
#snap-zone {
    position: fixed;
    top: 0;
    left: 0;
    right: 0;
    height: 80px;
    background: linear-gradient(to bottom, rgba(0, 242, 255, 0.25), transparent);
    opacity: 0;
