/* ========== CENTRAL CONTAINER & FUSION CARD ========== */
.container {
    position: absolute;
    inset: 0;
    pointer-events: none;
    display: flex;
    align-items: center;
    justify-content: center;
    perspective: 1200px;
    z-index: 10
}
.fusion-card {
